(function () {
  var COLORS = ['#3b82f6', '#22c55e', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#f97316', '#64748b'];
  var tooltipEl = null;

  function node(name, attrs, text) {
    var el = document.createElementNS('http://www.w3.org/2000/svg', name);
    Object.keys(attrs || {}).forEach(function (key) {
      el.setAttribute(key, attrs[key]);
    });
    if (text != null) el.textContent = text;
    return el;
  }

  function appendTitle(el, text) {
    if (!text) return;
    el.appendChild(node('title', null, text));
  }

  function ensureTooltip() {
    if (!tooltipEl) {
      tooltipEl = document.createElement('div');
      tooltipEl.className = 'chart-tooltip hidden';
      document.body.appendChild(tooltipEl);
    }
    return tooltipEl;
  }

  function showTooltip(event, title, lines) {
    var tip = ensureTooltip();
    var html = '';
    if (title) html += '<span class="chart-tooltip-title">' + title + '</span>';
    html += lines.map(function (line) { return '<div>' + line + '</div>'; }).join('');
    tip.innerHTML = html;
    tip.classList.remove('hidden');
    var x = event.clientX + 14;
    var y = event.clientY + 14;
    tip.style.left = x + 'px';
    tip.style.top = y + 'px';
  }

  function moveTooltip(event) {
    if (!tooltipEl || tooltipEl.classList.contains('hidden')) return;
    tooltipEl.style.left = event.clientX + 14 + 'px';
    tooltipEl.style.top = event.clientY + 14 + 'px';
  }

  function hideTooltip() {
    if (tooltipEl) tooltipEl.classList.add('hidden');
  }

  function bindTooltip(target, title, lines) {
    target.addEventListener('mouseenter', function (event) {
      showTooltip(event, title, lines);
    });
    target.addEventListener('mousemove', moveTooltip);
    target.addEventListener('mouseleave', hideTooltip);
  }

  function colorAt(index) {
    return COLORS[index % COLORS.length];
  }

  function colorAlpha(hex, alpha) {
    var raw = hex.replace('#', '');
    var full = raw.length === 3 ? raw.split('').map(function (s) { return s + s; }).join('') : raw;
    var r = parseInt(full.slice(0, 2), 16);
    var g = parseInt(full.slice(2, 4), 16);
    var b = parseInt(full.slice(4, 6), 16);
    return 'rgba(' + r + ',' + g + ',' + b + ',' + alpha + ')';
  }

  function gradient(svg, id, color, alphaStart, alphaEnd, vertical) {
    var defs = svg.querySelector('defs') || svg.insertBefore(node('defs'), svg.firstChild);
    var lg = node('linearGradient', {
      id: id,
      x1: vertical ? '0%' : '0%',
      y1: vertical ? '0%' : '0%',
      x2: vertical ? '0%' : '100%',
      y2: vertical ? '100%' : '0%'
    });
    lg.appendChild(node('stop', { offset: '0%', 'stop-color': colorAlpha(color, alphaStart) }));
    lg.appendChild(node('stop', { offset: '100%', 'stop-color': colorAlpha(color, alphaEnd) }));
    defs.appendChild(lg);
    return 'url(#' + id + ')';
  }

  function shouldShowAxisLabel(option, index, total) {
    var xAxis = option && option.xAxis;
    if (!xAxis) return true;
    if (Array.isArray(xAxis.labelIndexes) && xAxis.labelIndexes.length) {
      return xAxis.labelIndexes.indexOf(index) >= 0;
    }
    var step = Number(xAxis.labelStep) || 0;
    if (step > 1) return index % step === 0 || index === total - 1;
    return true;
  }

  function seriesColor(item, index) {
    return item && item.color ? item.color : colorAt(index);
  }

  function wrapCategoryLabel(label) {
    var text = String(label || '');
    if (text.length <= 8) return [text];
    var midpoint = Math.ceil(text.length / 2);
    return [text.slice(0, midpoint), text.slice(midpoint)];
  }

  function glossyOverlay(svg, id, vertical) {
    var defs = svg.querySelector('defs') || svg.insertBefore(node('defs'), svg.firstChild);
    var lg = node('linearGradient', {
      id: id,
      x1: vertical ? '0%' : '0%',
      y1: vertical ? '0%' : '0%',
      x2: vertical ? '0%' : '100%',
      y2: vertical ? '100%' : '0%'
    });
    lg.appendChild(node('stop', { offset: '0%', 'stop-color': 'rgba(255,255,255,.34)' }));
    lg.appendChild(node('stop', { offset: '34%', 'stop-color': 'rgba(255,255,255,.12)' }));
    lg.appendChild(node('stop', { offset: '100%', 'stop-color': 'rgba(255,255,255,0)' }));
    defs.appendChild(lg);
    return 'url(#' + id + ')';
  }

  function chartCeiling(value) {
    var numeric = Number(value) || 0;
    if (numeric <= 0) return 10;
    if (numeric <= 10) return Math.ceil(numeric + 2);
    if (numeric <= 50) return Math.ceil(numeric * 1.12);
    if (numeric <= 200) return Math.ceil(numeric * 1.08);
    return Math.ceil(numeric * 1.05);
  }

  function maxValue(series, stacked) {
    if (!series.length) return 10;
    if (stacked) {
      var len = Math.max.apply(null, series.map(function (s) { return (s.data || []).length; }));
      var totals = [];
      for (var i = 0; i < len; i += 1) {
        totals[i] = series.reduce(function (sum, item) { return sum + (Number((item.data || [])[i]) || 0); }, 0);
      }
      return chartCeiling(Math.max.apply(null, totals.concat([0])));
    }
    var values = [];
    series.forEach(function (item) {
      (item.data || []).forEach(function (value) {
        values.push(Number(value) || 0);
      });
    });
    return chartCeiling(Math.max.apply(null, values.concat([0])));
  }

  function axisSeries(series, axisIndex) {
    return (series || []).filter(function (item) {
      return Number(item.yAxisIndex || 0) === axisIndex;
    });
  }

  function maxValueForAxis(series, axisIndex) {
    var scoped = axisSeries(series, axisIndex);
    if (!scoped.length) return 10;
    return maxValue(scoped, false);
  }

  function createChart(dom) {
    return {
      dom: dom,
      option: null,
      resize: function () {
        if (this.option) this.setOption(this.option);
      },
      setOption: function (option) {
        this.option = option || {};
        render(dom, this.option);
      }
    };
  }

  function render(dom, option) {
    dom.classList.add('chart-host');
    dom.__chartInstance = dom.__chartInstance || createChart(dom);
    var rect = dom.getBoundingClientRect();
    var width = Math.max(320, Math.floor(rect.width || dom.clientWidth || 320));
    var height = Math.max(240, Math.floor(rect.height || dom.clientHeight || 240));
    var svg = node('svg', { viewBox: '0 0 ' + width + ' ' + height, width: '100%', height: '100%' });
    dom.innerHTML = '';
    dom.appendChild(svg);

    svg.appendChild(node('rect', {
      x: 0,
      y: 0,
      width: width,
      height: height,
      rx: 18,
      fill: 'rgba(7,19,43,0.45)'
    }));

    if (option.title && option.title.text) {
      svg.appendChild(node('text', { x: 18, y: 28, fill: '#dbeafe', 'font-size': 14, 'font-weight': 600 }, option.title.text));
    }

    var series = option.series || [];
    if (!series.length) return;
    var firstType = series[0].type || 'bar';
    if (firstType === 'pie') renderPie(svg, width, height, series[0].data || [], option, series[0]);
    else if (firstType === 'line') renderLine(svg, width, height, option, series);
    else renderBar(svg, width, height, option, series);
  }

  function legendPlacement(option) {
    var legend = option && option.legend;
    if (!legend || legend.show === false) return 'bottom-left';
    if (legend.top === 'top' && legend.right != null) return 'top-right';
    return 'bottom-left';
  }

  function renderAxes(svg, width, height, horizontal, hasLegend, legendPos) {
    var axis = horizontal
      ? {
          left: 92,
          right: width - 24,
          top: legendPos === 'top-right' ? 42 : 26,
          bottom: height - (hasLegend && legendPos !== 'top-right' ? 34 : 22)
        }
      : {
          left: 46,
          right: width - 18,
          top: legendPos === 'top-right' ? 54 : 38,
          bottom: height - (hasLegend && legendPos !== 'top-right' ? 44 : 34)
        };
    svg.appendChild(node('line', {
      x1: axis.left,
      y1: horizontal ? axis.top : axis.bottom,
      x2: horizontal ? axis.left : axis.right,
      y2: axis.bottom,
      stroke: 'rgba(148,163,184,.4)'
    }));
    svg.appendChild(node('line', {
      x1: axis.left,
      y1: axis.top,
      x2: axis.left,
      y2: axis.bottom,
      stroke: 'rgba(148,163,184,.4)'
    }));
    axis.plotWidth = axis.right - axis.left;
    axis.plotHeight = axis.bottom - axis.top;
    return axis;
  }

  function renderBar(svg, width, height, option, series) {
    var horizontal = option.yAxis && option.yAxis.data;
    var legendPos = legendPlacement(option);
    var axis = renderAxes(svg, width, height, horizontal, series.length > 1, legendPos);
    var labels = horizontal ? option.yAxis.data || [] : (option.xAxis && option.xAxis.data) || [];
    var stacked = series.length > 1 && series.some(function (s) { return !!s.stack; });
    var max = maxValue(series, stacked);
    if (horizontal) {
      var row = labels.length ? axis.plotHeight / labels.length : axis.plotHeight;
      labels.forEach(function (label, index) {
        var y = axis.top + row * index + row * 0.14;
        var xCursor = axis.left;
        var labelText = node('text', { x: 10, y: y + row * 0.34, fill: '#8aa0c5', 'font-size': 11 }, label);
        svg.appendChild(labelText);
        series.forEach(function (item, seriesIndex) {
          var value = Number((item.data || [])[index]) || 0;
          var barW = (value / max) * (axis.plotWidth - 10);
          var visibleBarW = Math.max(barW, 2);
          var pointColor = series.length === 1 ? colorAt(index) : colorAt(seriesIndex);
          var tipLines = item.tooltipLines && item.tooltipLines[index] ? item.tooltipLines[index] : [(item.name || '数值') + '：' + value];
          var rect = node('rect', {
            x: xCursor,
            y: y,
            width: visibleBarW,
            height: row * 0.56,
            rx: 8,
            fill: gradient(svg, 'barh-' + seriesIndex + '-' + index, pointColor, 0.95, 0.6, false),
            opacity: 0.95
          });
          appendTitle(rect, (item.name || label) + '：' + value);
          bindTooltip(rect, label, tipLines);
          svg.appendChild(rect);
          svg.appendChild(node('rect', {
            x: xCursor + 1,
            y: y + 1,
            width: Math.max(visibleBarW - 2, 1),
            height: Math.max(row * 0.18, 3),
            rx: 8,
            fill: glossyOverlay(svg, 'barh-gloss-' + seriesIndex + '-' + index, false),
            opacity: 0.95
          }));
          if (!stacked) {
            svg.appendChild(node('circle', {
              cx: xCursor + visibleBarW,
              cy: y + row * 0.28,
              r: 4.5,
              fill: pointColor,
              stroke: '#dbeafe',
              'stroke-width': 1.5,
              opacity: 0.98
            }));
            svg.appendChild(node('text', {
              x: xCursor + visibleBarW + 12,
              y: y + row * 0.34,
              fill: '#dbeafe',
              'font-size': 11
            }, value));
          }
          xCursor += stacked ? barW : 0;
          if (!stacked) {
            rect.setAttribute('y', y + seriesIndex * row * 0.24);
            rect.setAttribute('height', row * 0.24);
          }
        });
      });
      return;
    }

    var slot = labels.length ? axis.plotWidth / labels.length : axis.plotWidth;
    labels.forEach(function (label, index) {
      var xBase = axis.left + slot * index;
      var yBase = axis.bottom;
      var labelLines = wrapCategoryLabel(label);
      labelLines.forEach(function (line, lineIndex) {
        var xLabel = node('text', { x: xBase + slot / 2, y: axis.bottom + 19 + lineIndex * 11, 'text-anchor': 'middle', fill: '#8aa0c5', 'font-size': 10 }, line);
        svg.appendChild(xLabel);
      });
      svg.appendChild(node('line', {
        x1: xBase + slot * 0.12,
        y1: axis.bottom + 6,
        x2: xBase + slot * 0.88,
        y2: axis.bottom + 6,
        stroke: 'rgba(120,196,255,.14)',
        'stroke-width': 1
      }));
      if (stacked) {
        var stackHeight = 0;
        var stackTotal = 0;
        series.forEach(function (item, seriesIndex) {
          var value = Number((item.data || [])[index]) || 0;
          stackTotal += value;
          var barH = (value / max) * (axis.plotHeight - 16);
          var pointColor = series.length === 1 ? colorAt(index) : colorAt(seriesIndex);
          var tipLines = item.tooltipLines && item.tooltipLines[index] ? item.tooltipLines[index] : [(item.name || '数值') + '：' + value];
          var barX = xBase + slot * 0.14;
          var barY = yBase - stackHeight - barH;
          var barWidth = slot * 0.72;
          svg.appendChild(node('rect', {
            x: barX + slot * 0.015,
            y: barY + 3,
            width: Math.max(barWidth - slot * 0.03, 1),
            height: Math.max(barH, 4),
            rx: 0,
            fill: 'rgba(8, 15, 32, 0.16)'
          }));
          var rect = node('rect', {
            x: barX,
            y: barY,
            width: barWidth,
            height: Math.max(barH, 4),
            rx: 0,
            fill: gradient(svg, 'bars-' + seriesIndex + '-' + index, pointColor, 0.88, 0.72, true),
            opacity: 0.96
          });
          appendTitle(rect, label + ' / ' + (item.name || '') + '：' + value);
          bindTooltip(rect, label, tipLines);
          svg.appendChild(rect);
          svg.appendChild(node('rect', {
            x: barX + 2,
            y: barY + 1,
            width: Math.max(Math.min(barWidth * 0.18, 8), 2),
            height: Math.max(barH - 2, 2),
            rx: 0,
            fill: glossyOverlay(svg, 'bars-gloss-' + seriesIndex + '-' + index, true),
            opacity: 0.72
          }));
          stackHeight += barH;
        });
        svg.appendChild(node('text', {
          x: xBase + slot / 2,
          y: yBase - stackHeight - 8,
          'text-anchor': 'middle',
          fill: '#dbeafe',
          'font-size': 10,
          'font-weight': 600
        }, stackTotal));
      } else {
        series.forEach(function (item, seriesIndex) {
          var value = Number((item.data || [])[index]) || 0;
          var barH = (value / max) * (axis.plotHeight - 16);
          var pointColor = series.length === 1 ? colorAt(index) : colorAt(seriesIndex);
          var tipLines = item.tooltipLines && item.tooltipLines[index] ? item.tooltipLines[index] : [(item.name || '数值') + '：' + value];
          var barW = Math.min(slot * 0.22, 26);
          var x = xBase + slot * 0.18 + barW * seriesIndex * 1.25;
          var rect = node('rect', {
            x: x,
            y: yBase - barH,
            width: barW,
            height: Math.max(barH, 4),
            rx: 8,
            fill: gradient(svg, 'bar-' + seriesIndex + '-' + index, pointColor, 0.96, 0.58, true),
            opacity: 0.96
          });
          appendTitle(rect, label + ' / ' + (item.name || '') + '：' + value);
          bindTooltip(rect, label, tipLines);
          svg.appendChild(rect);
          if (slot > 70) {
            var vText = node('text', { x: x + barW / 2, y: yBase - barH - 6, 'text-anchor': 'middle', fill: '#dbeafe', 'font-size': 10 }, value);
            svg.appendChild(vText);
          }
        });
      }
    });
    renderLegend(svg, series, width, height, option);
  }

  function renderLine(svg, width, height, option, series) {
    var legendPos = legendPlacement(option);
    var axis = renderAxes(svg, width, height, false, series.length > 1, legendPos);
    var labels = (option.xAxis && option.xAxis.data) || [];
    var yAxes = Array.isArray(option.yAxis) ? option.yAxis : [option.yAxis || {}];
    var leftAxis = yAxes[0] || {};
    var rightAxis = yAxes[1] || null;
    var leftMax = maxValueForAxis(series, 0);
    var rightMax = rightAxis ? maxValueForAxis(series, 1) : leftMax;
    var step = labels.length > 1 ? axis.plotWidth / (labels.length - 1) : axis.plotWidth;

    function drawAxisTicks(side, max, axisOption, renderGrid) {
      var ticks = 4;
      var x = side === 'right' ? axis.right : axis.left;
      var textAnchor = side === 'right' ? 'start' : 'end';
      var textX = side === 'right' ? x + 8 : x - 8;
      if (side === 'right') {
        svg.appendChild(node('line', {
          x1: axis.right,
          y1: axis.top,
          x2: axis.right,
          y2: axis.bottom,
          stroke: 'rgba(148,163,184,.4)'
        }));
      }
      for (var tick = 0; tick <= ticks; tick += 1) {
        var ratio = tick / ticks;
        var y = axis.bottom - ratio * axis.plotHeight;
        var value = Math.round((max / ticks) * tick);
        if (renderGrid) {
          svg.appendChild(node('line', {
            x1: axis.left,
            y1: y,
            x2: axis.right,
            y2: y,
            stroke: 'rgba(148,163,184,' + (tick === 0 ? '.18' : '.08') + ')'
          }));
        }
        svg.appendChild(node('text', {
          x: textX,
          y: y + 4,
          'text-anchor': textAnchor,
          fill: '#8aa0c5',
          'font-size': 10
        }, value));
      }
      if (axisOption && axisOption.name) {
        svg.appendChild(node('text', {
          x: side === 'right' ? axis.right + 8 : axis.left - 8,
          y: axis.top - 10,
          'text-anchor': side === 'right' ? 'start' : 'end',
          fill: '#aac1e7',
          'font-size': 11,
          'font-weight': 600
        }, axisOption.name));
      }
    }

    drawAxisTicks('left', leftMax, leftAxis, true);
    if (rightAxis) drawAxisTicks('right', rightMax, rightAxis, false);

    labels.forEach(function (label, index) {
      if (!shouldShowAxisLabel(option, index, labels.length)) return;
      svg.appendChild(node('text', { x: axis.left + step * index, y: axis.bottom + 20, 'text-anchor': 'middle', fill: '#8aa0c5', 'font-size': 11 }, label));
    });

    series.forEach(function (item, seriesIndex) {
      var points = [];
      var areaPoints = [];
      var lineColor = seriesColor(item, seriesIndex);
      var emphasis = item.emphasisPoints || [];
      (item.data || []).forEach(function (value, index) {
        var numeric = Number(value) || 0;
        var x = axis.left + step * index;
        var axisIndex = Number(item.yAxisIndex || 0);
        var axisMax = axisIndex === 1 && rightAxis ? rightMax : leftMax;
        var y = axis.bottom - (numeric / axisMax) * (axis.plotHeight - 16);
        points.push(x + ',' + y);
        areaPoints.push(x + ',' + y);
        var pointRadius = item.pointRadius || 4;
        var circle = node('circle', { cx: x, cy: y, r: pointRadius, fill: lineColor, stroke: '#dbeafe', 'stroke-width': 1.5 });
        appendTitle(circle, (item.name || '') + ' ' + (labels[index] || '') + '：' + numeric);
        bindTooltip(circle, labels[index] || '', [(item.name || '数值') + '：' + numeric]);
        svg.appendChild(circle);
        emphasis.forEach(function (mark) {
          if (mark.index !== index) return;
          svg.appendChild(node('circle', { cx: x, cy: y, r: pointRadius + 3, fill: 'transparent', stroke: mark.stroke || '#8cf0ff', 'stroke-width': 2, opacity: 0.95 }));
          svg.appendChild(node('text', { x: x, y: y - 14, 'text-anchor': 'middle', fill: mark.fill || '#8cf0ff', 'font-size': 10, 'font-weight': 600 }, mark.label || numeric));
        });
        if (step > 70 && item.showValueLabel !== false) {
          svg.appendChild(node('text', { x: x, y: y - 8, 'text-anchor': 'middle', fill: '#dbeafe', 'font-size': 10 }, numeric));
        }
      });
      if (item.areaStyle) {
        areaPoints.push(axis.left + step * ((item.data || []).length - 1) + ',' + axis.bottom);
        areaPoints.push(axis.left + ',' + axis.bottom);
        svg.appendChild(node('polygon', {
          points: areaPoints.join(' '),
          fill: gradient(svg, 'area-' + seriesIndex, lineColor, item.areaAlphaStart || 0.28, item.areaAlphaEnd || 0.02, true),
          opacity: item.areaOpacity || 0.16
        }));
      }
      svg.appendChild(node('polyline', {
        points: points.join(' '),
        fill: 'none',
        stroke: colorAlpha(lineColor, item.lineGlow || 0.16),
        'stroke-width': (item.lineWidth || 3) + 4,
        'stroke-linecap': 'round',
        'stroke-linejoin': 'round'
      }));
      svg.appendChild(node('polyline', {
        points: points.join(' '),
        fill: 'none',
        stroke: lineColor,
        'stroke-width': item.lineWidth || 3,
        'stroke-linecap': 'round',
        'stroke-linejoin': 'round'
      }));
    });
    renderLegend(svg, series, width, height, option);
  }

  function renderPie(svg, width, height, items, option, seriesOption) {
    var total = items.reduce(function (sum, item) { return sum + (Number(item.value) || 0); }, 0) || 1;
    var center = (seriesOption && seriesOption.center) || ['66%', '55%'];
    var radiusRatio = (seriesOption && seriesOption.radius) || 0.22;
    var innerRatio = (seriesOption && seriesOption.innerRadius) || 0;
    var centerX = typeof center[0] === 'string' && center[0].indexOf('%') > -1 ? width * parseFloat(center[0]) / 100 : Number(center[0] || width * 0.66);
    var centerY = typeof center[1] === 'string' && center[1].indexOf('%') > -1 ? height * parseFloat(center[1]) / 100 : Number(center[1] || height * 0.55);
    var radius = Math.min(width, height) * radiusRatio;
    var innerRadius = Math.min(width, height) * innerRatio;
    var current = -90;
    var legendY = 44;

    items.forEach(function (item, index) {
      var value = Number(item.value) || 0;
      var angle = (value / total) * 360;
      var start = current * Math.PI / 180;
      var end = (current + angle) * Math.PI / 180;
      var startX = centerX + Math.cos(start) * radius;
      var startY = centerY + Math.sin(start) * radius;
      var endX = centerX + Math.cos(end) * radius;
      var endY = centerY + Math.sin(end) * radius;
      var largeArc = angle > 180 ? 1 : 0;
      var path;
      if (innerRadius > 0) {
        var innerStartX = centerX + Math.cos(start) * innerRadius;
        var innerStartY = centerY + Math.sin(start) * innerRadius;
        var innerEndX = centerX + Math.cos(end) * innerRadius;
        var innerEndY = centerY + Math.sin(end) * innerRadius;
        path = ['M', startX, startY, 'A', radius, radius, 0, largeArc, 1, endX, endY, 'L', innerEndX, innerEndY, 'A', innerRadius, innerRadius, 0, largeArc, 0, innerStartX, innerStartY, 'Z'].join(' ');
      } else {
        path = ['M', centerX, centerY, 'L', startX, startY, 'A', radius, radius, 0, largeArc, 1, endX, endY, 'Z'].join(' ');
      }
      var sector = node('path', { d: path, fill: colorAt(index), opacity: 0.96 });
      appendTitle(sector, (item.name || '分类') + '：' + value);
      bindTooltip(sector, item.name || '分类', ['数量：' + value, '占比：' + ((value / total) * 100).toFixed(1) + '%']);
      bindTooltip(sector, item.name || '分类', item.tooltipLines || ['数量：' + value, '占比：' + ((value / total) * 100).toFixed(1) + '%']);
      svg.appendChild(sector);
      svg.appendChild(node('rect', { x: 24, y: legendY - 10, width: 10, height: 10, rx: 2, fill: colorAt(index) }));
      svg.appendChild(node('text', { x: 40, y: legendY, fill: '#dbeafe', 'font-size': 12 }, (item.name || '分类') + '  ' + value));
      legendY += 20;
      current += angle;
    });
    if (innerRadius > 0) {
      svg.appendChild(node('circle', { cx: centerX, cy: centerY, r: innerRadius - 2, fill: 'rgba(7,19,43,0.92)', stroke: 'rgba(120,196,255,.18)', 'stroke-width': 1 }));
      svg.appendChild(node('text', { x: centerX, y: centerY - 6, 'text-anchor': 'middle', fill: '#8aa0c5', 'font-size': 11 }, (seriesOption && seriesOption.centerTitle) || '总量'));
      svg.appendChild(node('text', { x: centerX, y: centerY + 16, 'text-anchor': 'middle', fill: '#eef6ff', 'font-size': 20, 'font-weight': 700 }, (seriesOption && seriesOption.centerValue) || total));
    }
  }

  function renderLegend(svg, series, width, height, option) {
    if (option && option.legend && option.legend.show === false) return;
    if (!series || series.length <= 1) return;
    var legendPos = legendPlacement(option);
    var metrics = series.map(function (item, index) {
      var text = item.name || ('系列' + (index + 1));
      return { text: text, width: text.length * 11 + 20 };
    });
    var totalWidth = metrics.reduce(function (sum, item) { return sum + item.width; }, 0) + Math.max(0, (metrics.length - 1) * 12);
    var x = legendPos === 'top-right' ? Math.max(22, width - totalWidth - 26) : 22;
    var y = legendPos === 'top-right' ? 26 : height - 18;
    series.forEach(function (item, index) {
      svg.appendChild(node('circle', { cx: x, cy: y - 4, r: 3.5, fill: seriesColor(item, index) }));
      svg.appendChild(node('text', { x: x + 8, y: y, fill: '#8aa0c5', 'font-size': 10 }, item.name || ('系列' + (index + 1))));
      x += metrics[index].width + 12;
    });
  }

  window.echarts = {
    init: function (dom) {
      var chart = dom.__chartInstance || createChart(dom);
      dom.__chartInstance = chart;
      return chart;
    },
    graphic: { LinearGradient: function () {} }
  };

  window.addEventListener('resize', function () {
    document.querySelectorAll('.chart-host').forEach(function (dom) {
      if (dom.__chartInstance) dom.__chartInstance.resize();
    });
  });
})();


